        t = self._tokens(sem)
        return "memory" in t and any(w in t for w in ["your", "you", "aurora", "system"])

    def _about_user_memory(self, sem: SemanticFrame) -> bool:
        t = self._tokens(sem)
        return "memory" in t and any(w in t for w in ["my", "mine"])

    def _about_identity(self, sem: SemanticFrame) -> bool:
        txt = sem.raw_text.lower()
        return "who are you" in txt or "what are you" in txt or "what is your purpose" in txt

    def _about_emotion(self, sem: SemanticFrame) -> bool:
        txt = sem.raw_text.lower()
        return "emotion" in txt or "feel" in txt or "feeling" in txt

