        if name_intent == "INTENT_CONVERSATIONAL_FILLER":
            return self._answer_filler(user_text, sem, emotion)

        if name_intent == "INTENT_CONCEPT_UNKNOWN":
            return self._answer_unknown(user_text, sem)

        # Fallback
        return self._answer_unknown(user_text, sem)

