#!/usr/bin/env python3
"""
Aurora Autonomous Voice Core
============================

Polls ".aurora_voice_inbox.jsonl" and speaks any lines it finds.
Uses pyttsx3 if available; otherwise prints to console.
"""

import os
import time
import queue

try:
    import pyttsx3
except Exception:
    pyttsx3 = None


class AuroraAutonomousVoiceCore:
    def __init__(self, project_root: str):
        self.project_root = os.path.abspath(project_root)
        self.outbox = queue.Queue()
        self.engine = None
        if pyttsx3:
            try:
                self.engine = pyttsx3.init()
            except Exception:
                self.engine = None

    def speak(self, text: str) -> None:
        self.outbox.put(text)

    def _speak_now(self, text: str) -> None:
        if self.engine:
            try:
                self.engine.say(text)
                self.engine.runAndWait()
            except Exception:
                print(f"[AURORA-VOICE] {text}")
        else:
            print(f"[AURORA-VOICE] {text}")

    def tick(self) -> None:
        inbox_path = os.path.join(self.project_root, ".aurora_voice_inbox.jsonl")
        if os.path.exists(inbox_path):
            with open(inbox_path, "r", encoding="utf-8") as f:
                lines = f.readlines()
            if lines:
                with open(inbox_path, "w", encoding="utf-8") as f:
                    f.write("")
            for line in lines:
                line = line.strip()
                if not line:
                    continue
                self.speak(line)

        while not self.outbox.empty():
            msg = self.outbox.get()
            self._speak_now(msg)

    def run_forever(self, interval: float = 1.0) -> None:
        while True:
            self.tick()
            time.sleep(interval)
