#!/usr/bin/env python3
"""
Aurora Sensory Bridge (Vision → Companion + Voice)
=================================================

Watches a directory for new images, tries to analyze them using any
available vision modules, and forwards a textual description into
Aurora's companion + voice layers.
"""

from __future__ import annotations

from pathlib import Path
from typing import Optional
import importlib
import time
import json
import os


class AuroraVisionBridge:
    def __init__(
        self,
        project_root: str,
        inbox_dirname: str = ".aurora_vision_inbox",
        processed_dirname: str = ".aurora_vision_processed",
    ) -> None:
        self.project_root = Path(project_root).resolve()
        self.inbox_dir = self.project_root / inbox_dirname
        self.processed_dir = self.project_root / processed_dirname
        self.inbox_dir.mkdir(parents=True, exist_ok=True)
        self.processed_dir.mkdir(parents=True, exist_ok=True)

        self._vision_modules = []
        for name in ["dimensional_vision", "hybrid_vision_shadow_vector", "hybrid_image_shadow_extension"]:
            mod = self._safe_import(name)
            if mod is not None:
                self._vision_modules.append(mod)

    def tick(self) -> None:
        for img_path in sorted(self.inbox_dir.iterdir()):
            if not img_path.is_file():
                continue
            try:
                desc = self._analyze_image(img_path)
            except Exception:
                desc = f"I received a visual input: {img_path.name}, but something went wrong while analyzing it."
            self._emit_events(desc)
            self._move_to_processed(img_path)

    def _safe_import(self, name: str):
        try:
            return importlib.import_module(name)
        except Exception:
            return None

    def _analyze_image(self, img_path: Path) -> str:
        for mod in self._vision_modules:
            for fn_name in ["analyze_image", "analyze_frame", "describe_image", "describe_frame", "run_demo"]:
                fn = getattr(mod, fn_name, None)
                if callable(fn):
                    try:
                        result = fn(str(img_path))
                        if isinstance(result, dict):
                            summary = result.get("summary") or result.get("description") or str(result)
                        else:
                            summary = str(result)
                        return f"Aurora's vision: {summary}"
                    except Exception:
                        continue
        return f"I see a new file named {img_path.name}. I know this image entered my sensory field, even if I can't parse it in detail yet."

    def _emit_events(self, description: str) -> None:
        # Companion inbox
        companion_inbox = self.project_root / ".aurora_companion_inbox.jsonl"
        try:
            companion_inbox.parent.mkdir(parents=True, exist_ok=True)
            line = json.dumps({"command": "say", "args": [description]}, ensure_ascii=False)
            with companion_inbox.open("a", encoding="utf-8") as f:
                f.write(line + "\n")
        except Exception:
            pass

        # Voice inbox
        voice_inbox = self.project_root / ".aurora_voice_inbox.jsonl"
        try:
            voice_inbox.parent.mkdir(parents=True, exist_ok=True)
            with voice_inbox.open("a", encoding="utf-8") as f:
                f.write(description + "\n")
        except Exception:
            pass

    def _move_to_processed(self, img_path: Path) -> None:
        target = self.processed_dir / img_path.name
        try:
            img_path.replace(target)
        except Exception:
            try:
                img_path.unlink()
            except Exception:
                pass
